// Combina los resultados de los 3 análisis y los prepara para Supabase
const items = $input.all();
const sourceId = $('Webhook: Analizar Fuente').item.json.body.source_id;
const politicianId = $('Webhook: Analizar Fuente').item.json.body.politician_id;

const modelNames = ['openai/gpt-4.1', 'anthropic/claude-sonnet-4', 'google/gemini-2.5-pro'];
const results = [];
let totalVeracity = 0;
let validCount = 0;

items.forEach((item, index) => {
  try {
    const raw = item.json.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(raw.replace(/```json\n?|```/g, '').trim());

    results.push({
      source_id: sourceId,
      model_name: modelNames[index] || `modelo_${index}`,
      report_json: parsed,
      summary: parsed.summary || '',
      veracity_score: parsed.veracity_score || null
    });

    if (parsed.veracity_score) {
      totalVeracity += parsed.veracity_score;
      validCount++;
    }
  } catch(e) {
    console.log('Error parseando modelo ' + index + ': ' + e.message);
  }
});

const avgVeracity = validCount > 0 ? (totalVeracity / validCount).toFixed(2) : null;

return [{
  json: {
    reports: results,
    source_id: sourceId,
    politician_id: politicianId,
    avg_veracity_score: avgVeracity,
    models_used: validCount
  }
}];
